   252→    /**
   253→     * Given a top path in the filesystem, return a list of paths to archives (JAR or ZIP
   254→     * files) contained under this top path. If the top path contains only java class files,
   255→     * return the top path itself. This method follows symbolic links to discover archives and
   256→     * returns the such archives as absolute paths.
   257→     *
   258→     * @param topPath the path to use as root of plugin search.
   259→     * @return a list of potential plugin paths, or empty list if no such paths exist.
   260→     * @throws IOException
   261→     */
   262→    public static List<Path> pluginUrls(Path topPath) throws IOException {
   263→        boolean containsClassFiles = false;
   264→        Set<Path> archives = new TreeSet<>();
   265→        LinkedList<DirectoryEntry> dfs = new LinkedList<>();
   266→        Set<Path> visited = new HashSet<>();
   267→
   268→        if (isArchive(topPath)) {
   269→            return Collections.singletonList(topPath);
   270→        }
   271→
   272→        DirectoryStream<Path> topListing = Files.newDirectoryStream(
   273→                topPath,
   274→                PLUGIN_PATH_FILTER
   275→        );
   276→        dfs.push(new DirectoryEntry(topListing));
   277→        visited.add(topPath);
   278→        try {
   279→            while (!dfs.isEmpty()) {
   280→                Iterator<Path> neighbors = dfs.peek().iterator;
   281→                if (!neighbors.hasNext()) {
   282→                    dfs.pop().stream.close();
   283→                    continue;
   284→                }
   285→
   286→                Path adjacent = neighbors.next();
   287→                if (Files.isSymbolicLink(adjacent)) {
   288→                    try {
   289→                        Path symlink = Files.readSymbolicLink(adjacent);
   290→                        // if symlink is absolute resolve() returns the absolute symlink itself
   291→                        Path parent = adjacent.getParent();
   292→                        if (parent == null) {
   293→                            continue;
   294→                        }
   295→                        Path absolute = parent.resolve(symlink).toRealPath();
   296→                        if (Files.exists(absolute)) {
   297→                            adjacent = absolute;
   298→                        } else {
   299→                            continue;
   300→                        }
   301→                    } catch (IOException e) {
   302→                        // See https://issues.apache.org/jira/browse/KAFKA-6288 for a reported
   303→                        // failure. Such a failure at this stage is not easily reproducible and
   304→                        // therefore an exception is caught and ignored after issuing a
   305→                        // warning. This allows class scanning to continue for non-broken plugins.
   306→                        log.warn(
   307→                                "Resolving symbolic link '{}' failed. Ignoring this path.",
   308→                                adjacent,
   309→                                e
   310→                        );
   311→                        continue;
   312→                    }
   313→                }
   314→
   315→                if (!visited.contains(adjacent)) {
   316→                    visited.add(adjacent);
   317→                    if (isArchive(adjacent)) {
   318→                        archives.add(adjacent);
   319→                    } else if (isClassFile(adjacent)) {
   320→                        containsClassFiles = true;
   321→                    } else {
   322→                        DirectoryStream<Path> listing = Files.newDirectoryStream(
   323→                                adjacent,
   324→                                PLUGIN_PATH_FILTER
   325→                        );
   326→                        dfs.push(new DirectoryEntry(listing));
   327→                    }
   328→                }
   329→            }
   330→        } finally {
   331→            while (!dfs.isEmpty()) {
   332→                dfs.pop().stream.close();
   333→            }
   334→        }
   335→
   336→        if (containsClassFiles) {
   337→            if (archives.isEmpty()) {
   338→                return Collections.singletonList(topPath);
   339→            }
   340→            log.warn("Plugin path contains both java archives and class files. Returning only the"
   341→                    + " archives");
   342→        }
   343→        return Arrays.asList(archives.toArray(new Path[0]));
   344→    }
